/// Parses the platform-channel shape used by Android connect intents.
///
/// Native code may deliver either a plain payload string or a map containing
/// the payload plus handoff provenance metadata.
SetupQrImageImport? parseNavivoxConnectIntentPayload(Object? payload) {
  final normalized = _NavivoxPlatformConnectIntentPayload.from(payload);
  if (normalized == null) return null;

  final parsed = parseNavivoxConnectionImportPayload(normalized.text);
  if (parsed == null) return null;
  return parsed.withSource(normalized.source);
}

class _NavivoxPlatformConnectIntentPayload {
  const _NavivoxPlatformConnectIntentPayload({
    required this.text,
    required this.source,
  });

  final String text;
  final PairingHandoffSource source;

  static _NavivoxPlatformConnectIntentPayload? from(Object? payload) {
    if (payload is String) return _fromString(payload);
    if (payload is Map) return _fromMap(payload);
    return null;
  }

  static _NavivoxPlatformConnectIntentPayload? _fromString(String payload) {
    final text = payload.trim();
    if (text.isEmpty) return null;
    return _NavivoxPlatformConnectIntentPayload(
      text: text,
      source: PairingHandoffSource.manual,
    );
  }

  static _NavivoxPlatformConnectIntentPayload? _fromMap(Map payload) {
    final rawText = payload['payload'];
    if (rawText is! String) return null;
    final text = rawText.trim();
    if (text.isEmpty) return null;
    return _NavivoxPlatformConnectIntentPayload(
      text: text,
      source: pairingHandoffSourceFromPlatformPayload(payload['source']),
    );
  }
}

PairingHandoffSource pairingHandoffSourceFromPlatformPayload(Object? value) {
  return switch (value?.toString().trim()) {
    'direct_app_open' => PairingHandoffSource.directAppOpen,
    'shared_text' => PairingHandoffSource.sharedText,
    _ => PairingHandoffSource.manual,
  };
}

class NavivoxInitialConnectIntentPayloadCache {
  Object? _payload;
  bool _hasPayload = false;

  bool get hasPayload => _hasPayload;

  void remember(Object? payload) {
    _payload = payload;
    _hasPayload = true;
  }

  Object? take() {
    final payload = _payload;
    _payload = null;
    _hasPayload = false;
    return payload;
  }
}

String? _firstNonBlankQueryParameterValue(List<String> values) {
  for (final value in values) {
    final text = navivoxOptionalLiteralStringFromJson(value);
    if (text != null) return text;
  }
  return null;
}

String? _baseUrlFromGenericUri(Uri uri) {
  return switch (uri.scheme) {
    'http' || 'https' => navivoxOriginFromUri(uri),
    'ws' || 'wss' => _webSocketUriBaseUrl(uri),
    _ => null,
  };
}

bool _isWebSocketUri(Uri uri) => uri.scheme == 'ws' || uri.scheme == 'wss';

String? _webSocketUriBaseUrl(Uri uri) {
  try {
    return navivoxHttpBaseUrlFromEndpointUri(uri);
  } on FormatException {
    return null;
  }
}

class _ConnectionImportCandidate {
  const _ConnectionImportCandidate({
    this.baseUrl,
    this.token,
    this.webSocketUrl,
    this.serverId,
    this.profileId,
  });

  final String? baseUrl;
  final String? token;
  final String? webSocketUrl;
  final String? serverId;
  final String? profileId;

  bool get hasImportValues => baseUrl != null || token != null;

  bool get hasCompleteConnection => baseUrl != null && token != null;

  _ConnectionImportCandidateRank get rank => _ConnectionImportCandidateRank(
    isCompleteConnection: hasCompleteConnection,
    fieldScore: _fieldScore,
  );

  int get _fieldScore {
    var result = 0;
    if (baseUrl != null) result += 2;
    if (token != null) result += 2;
    if (webSocketUrl != null) result += 1;
    if (serverId != null) result += 1;
    if (profileId != null) result += 1;
    return result;
  }

  bool isRicherThan(_ConnectionImportCandidate? other) {
    return other == null || rank.isRicherThan(other.rank);
  }

  SetupQrImageImport toImport() {
    return SetupQrImageImport(
      baseUrl: baseUrl,
      token: token,
      webSocketUrl: webSocketUrl,
      serverId: serverId,
      profileId: profileId,
    );
  }
}

class _ConnectionImportCandidateRank {
  const _ConnectionImportCandidateRank({
    required this.isCompleteConnection,
    required this.fieldScore,
  });

  final bool isCompleteConnection;
  final int fieldScore;

  bool isRicherThan(_ConnectionImportCandidateRank other) {
    if (isCompleteConnection != other.isCompleteConnection) {
      return isCompleteConnection;
    }
    return fieldScore > other.fieldScore;
  }
}

_ConnectionImportCandidate _richerConnectionImportCandidate({
  required _ConnectionImportCandidate? currentBest,
  required _ConnectionImportCandidate candidate,
}) {
  // A complete baseUrl+token candidate can still be lower-fidelity than a later
  // complete candidate carrying provenance metadata. Selection therefore scores
  // all candidates instead of short-circuiting at the first complete import.
  return candidate.isRicherThan(currentBest) ? candidate : currentBest!;
}

